package config

import (
	"encoding/json"
	"fmt"
	"slices"
	"strings"
	"time"

	"github.com/jandedobbeleer/oh-my-posh/src/cache"
	"github.com/jandedobbeleer/oh-my-posh/src/color"
	"github.com/jandedobbeleer/oh-my-posh/src/log"
	"github.com/jandedobbeleer/oh-my-posh/src/regex"
	"github.com/jandedobbeleer/oh-my-posh/src/runtime"
	runjobs "github.com/jandedobbeleer/oh-my-posh/src/runtime/jobs"
	"github.com/jandedobbeleer/oh-my-posh/src/segments/options"
	"github.com/jandedobbeleer/oh-my-posh/src/template"

	"go.yaml.in/yaml/v3"
	c "golang.org/x/text/cases"
	"golang.org/x/text/language"
)

// SegmentStyle the style of segment, for more information, see the constants
type SegmentStyle string

func (s *SegmentStyle) resolve(context any) SegmentStyle {
	value, err := template.Render(string(*s), context)

	// default to Plain
	if err != nil || value == "" {
		return Plain
	}

	return SegmentStyle(value)
}

type Segment struct {
	writer                 SegmentWriter
	env                    runtime.Environment
	Options                options.Map `json:"options,omitempty" toml:"options,omitempty" yaml:"options,omitempty"`
	Properties             options.Map `json:"-" toml:"properties,omitempty" yaml:"-"`
	Cache                  *Cache      `json:"cache,omitempty" toml:"cache,omitempty" yaml:"cache,omitempty"`
	Alias                  string      `json:"alias,omitempty" toml:"alias,omitempty" yaml:"alias,omitempty"`
	styleCache             SegmentStyle
	foregroundCache        color.Ansi
	backgroundCache        color.Ansi
	name                   string
	LeadingDiamond         string         `json:"leading_diamond,omitempty" toml:"leading_diamond,omitempty" yaml:"leading_diamond,omitempty"`
	TrailingDiamond        string         `json:"trailing_diamond,omitempty" toml:"trailing_diamond,omitempty" yaml:"trailing_diamond,omitempty"`
	Template               string         `json:"template,omitempty" toml:"template,omitempty" yaml:"template,omitempty"`
	RightTemplate          string         `json:"right_template,omitempty" toml:"right_template,omitempty" yaml:"right_template,omitempty"`
	Foreground             color.Ansi     `json:"foreground,omitempty" toml:"foreground,omitempty" yaml:"foreground,omitempty"`
	TemplatesLogic         template.Logic `json:"templates_logic,omitempty" toml:"templates_logic,omitempty" yaml:"templates_logic,omitempty"`
	PowerlineSymbol        string         `json:"powerline_symbol,omitempty" toml:"powerline_symbol,omitempty" yaml:"powerline_symbol,omitempty"`
	Background             color.Ansi     `json:"background,omitempty" toml:"background,omitempty" yaml:"background,omitempty"`
	Filler                 string         `json:"filler,omitempty" toml:"filler,omitempty" yaml:"filler,omitempty"`
	Type                   SegmentType    `json:"type,omitempty" toml:"type,omitempty" yaml:"type,omitempty"`
	Style                  SegmentStyle   `json:"style,omitempty" toml:"style,omitempty" yaml:"style,omitempty"`
	LeadingPowerlineSymbol string         `json:"leading_powerline_symbol,omitempty" toml:"leading_powerline_symbol,omitempty" yaml:"leading_powerline_symbol,omitempty"`
	Placeholder            string         `json:"placeholder,omitempty" toml:"placeholder,omitempty" yaml:"placeholder,omitempty"`
	FallbackTemplate       string         `json:"fallback_template,omitempty" toml:"fallback_template,omitempty" yaml:"fallback_template,omitempty"`
	Tips                   []string       `json:"tips,omitempty" toml:"tips,omitempty" yaml:"tips,omitempty"`
	BackgroundTemplates    template.List  `json:"background_templates,omitempty" toml:"background_templates,omitempty" yaml:"background_templates,omitempty"`
	Templates              template.List  `json:"templates,omitempty" toml:"templates,omitempty" yaml:"templates,omitempty"`
	ExcludeFolders         []string       `json:"exclude_folders,omitempty" toml:"exclude_folders,omitempty" yaml:"exclude_folders,omitempty"`
	IncludeFolders         []string       `json:"include_folders,omitempty" toml:"include_folders,omitempty" yaml:"include_folders,omitempty"`
	Needs                  []string       `json:"-" toml:"-" yaml:"-"`
	ForegroundTemplates    template.List  `json:"foreground_templates,omitempty" toml:"foreground_templates,omitempty" yaml:"foreground_templates,omitempty"`
	Index                  int            `json:"index,omitempty" toml:"index,omitempty" yaml:"index,omitempty"`
	MinWidth               int            `json:"min_width,omitempty" toml:"min_width,omitempty" yaml:"min_width,omitempty"`
	Duration               time.Duration  `json:"-" toml:"-" yaml:"-"`
	NameLength             int            `json:"-" toml:"-" yaml:"-"`
	MaxWidth               int            `json:"max_width,omitempty" toml:"max_width,omitempty" yaml:"max_width,omitempty"`
	Timeout                int            `json:"timeout,omitempty" toml:"timeout,omitempty" yaml:"timeout,omitempty"`
	Newline                bool           `json:"newline,omitempty" toml:"newline,omitempty" yaml:"newline,omitempty"`
	Enabled                bool           `json:"-" toml:"-" yaml:"-"`
	InvertPowerline        bool           `json:"invert_powerline,omitempty" toml:"invert_powerline,omitempty" yaml:"invert_powerline,omitempty"`
	Force                  bool           `json:"force,omitempty" toml:"force,omitempty" yaml:"force,omitempty"`
	restored               bool           `json:"-" toml:"-" yaml:"-"`
	Toggled                bool           `json:"toggled,omitempty" toml:"toggled,omitempty" yaml:"toggled,omitempty"`
	Pending                bool           `json:"-" toml:"-" yaml:"-"`
	// Killed is set by the engine when the segment's timeout expired and its
	// child processes were killed; it blocks fallback_template rendering.
	Killed             bool `json:"-" toml:"-" yaml:"-"`
	Interactive        bool `json:"interactive,omitempty" toml:"interactive,omitempty" yaml:"interactive,omitempty"`
	foregroundResolved bool
	backgroundResolved bool
	needsEvaluated     bool
	evaluated          bool
}

// segmentAlias is used to avoid recursion during unmarshaling
type segmentAlias Segment

// segmentAux is a helper struct that captures the legacy 'properties' field
type segmentAux struct {
	Properties options.Map `json:"properties,omitempty" yaml:"properties,omitempty" toml:"properties,omitempty"`
	*segmentAlias
}

func (segment *Segment) UnmarshalJSON(data []byte) error {
	aux := &segmentAux{
		segmentAlias: (*segmentAlias)(segment),
	}

	if err := json.Unmarshal(data, aux); err != nil {
		return err
	}

	// Migrate 'properties' to 'options' if present
	if len(aux.Properties) > 0 && len(segment.Options) == 0 {
		segment.Options = aux.Properties
	}

	return nil
}

func (segment *Segment) UnmarshalYAML(node *yaml.Node) error {
	// Decode into a map to handle field renaming
	var raw map[string]any
	if err := node.Decode(&raw); err != nil {
		return err
	}

	// If 'properties' exists and 'options' doesn't, rename it
	if props, hasProps := raw["properties"]; hasProps {
		if _, hasOptions := raw["options"]; !hasOptions {
			raw["options"] = props
			delete(raw, "properties")
		}
	}

	// Re-encode and decode into the struct
	modifiedNode := &yaml.Node{}
	if err := modifiedNode.Encode(raw); err != nil {
		return err
	}

	return modifiedNode.Decode((*segmentAlias)(segment))
}

// MigratePropertiesToOptions migrates the deprecated Properties field to Options.
// This is needed for TOML configs since go-toml/v2 doesn't support custom unmarshalers.
func (segment *Segment) MigratePropertiesToOptions() {
	if len(segment.Properties) > 0 && len(segment.Options) == 0 {
		segment.Options = segment.Properties
		segment.Properties = nil
	}
}

func (segment *Segment) Name() string {
	if len(segment.name) != 0 {
		return segment.name
	}

	name := segment.Alias
	if name == "" {
		name = c.Title(language.English).String(string(segment.Type))
	}

	segment.name = name
	return name
}

func (segment *Segment) Execute(env runtime.Environment) {
	// segment timings for debug purposes
	var start time.Time
	if env.Flags().Debug {
		start = time.Now()
		segment.NameLength = len(segment.Name())
		defer func() {
			segment.Duration = time.Since(start)
		}()
	}

	defer segment.evaluateNeeds()

	err := segment.MapSegmentWithWriter(env)
	if err != nil || !segment.shouldIncludeFolder() {
		return
	}

	log.Debugf("segment: %s", segment.Name())

	if segment.isToggled() {
		return
	}

	if segment.restoreData() {
		return
	}

	cacheRestored := segment.restoreCache()
	if cacheRestored && !env.Flags().Streaming {
		return
	}

	if shouldHideForWidth(segment.env, segment.MinWidth, segment.MaxWidth) {
		return
	}

	defer func() {
		if segment.Enabled {
			template.Cache.AddSegmentData(segment.Name(), segment.writer)
		}
	}()

	// Only segments with a timeout can ever be killed via
	// KillGoroutineChildren (see prompt/segments.go executeSegmentWithTimeout),
	// so only those need a Job object to track/terminate their child
	// processes. Skipping this for the common case (no timeout configured)
	// avoids two syscalls + a map insert per segment per prompt.
	if segment.Timeout > 0 {
		if err := runjobs.CreateJobForGoroutine(segment.Name()); err != nil {
			log.Errorf("failed to create job for goroutine (segment: %s): %v", segment.Name(), err)
		}

		// Release the Job object (Windows) once this goroutine is done
		// spawning/waiting on children. cmd.Run blocks until its child exits,
		// so by the time Execute returns - on any path below, including a
		// panic unwind - no process we intended to keep alive is still
		// assigned to the job, making it safe to close despite
		// JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE. If the timeout path already
		// terminated/closed the job concurrently, this is a no-op; see the
		// ownership invariant documented on jobs.CloseGoroutineJob.
		defer runjobs.CloseGoroutineJob()
	}

	segment.Enabled = segment.writer.Enabled()
	segment.evaluated = true
}

func (segment *Segment) Render(index int, force bool) bool {
	// Allow pending segments to render (they'll show "..." text)
	if !segment.Pending && !segment.Enabled && !force {
		return segment.renderFallback(index)
	}

	if force {
		segment.Force = true
	}

	// Foreground/background may be overridden directly (e.g. color cycling) between
	// render passes, so the memoized values must not survive across calls to Render.
	segment.foregroundResolved = false
	segment.backgroundResolved = false

	segment.writer.SetIndex(index)

	text := segment.string()

	// Only update Enabled if segment is NOT pending (avoid race with Execute goroutine)
	if !segment.Pending {
		segment.Enabled = segment.Force || strings.ContainsFunc(text, func(r rune) bool { return r != ' ' })

		if !segment.Enabled {
			template.Cache.RemoveSegmentData(segment.Name())
			return false
		}
	}

	segment.SetText(text)
	segment.setCache()

	// We do this to make `.Text` available for a cross-segment reference in an extra prompt.
	template.Cache.AddSegmentData(segment.Name(), segment.writer)

	return true
}

// renderFallback attempts to render FallbackTemplate when a segment would
// otherwise be hidden because its writer's Enabled() returned false. It
// requires the writer to have completed its evaluation; segments hidden for other
// reasons (toggled off, folder include/exclude, width constraints, or a
// writer mapping error) never set evaluated, so they keep the silent-omission
// behavior. Segments killed by their timeout are excluded via Killed rather
// than evaluated, because their Execute goroutine keeps running after the
// kill and may still complete the evaluation before rendering starts.
func (segment *Segment) renderFallback(index int) bool {
	if segment.FallbackTemplate == "" || !segment.evaluated || segment.Killed {
		return false
	}

	text, err := template.Render(segment.FallbackTemplate, segment.writer)
	if err != nil {
		text = err.Error()
	}

	if !strings.ContainsFunc(text, func(r rune) bool { return r != ' ' }) {
		return false
	}

	// Foreground/background may be overridden directly (e.g. color cycling) between
	// render passes, so the memoized values must not survive across calls to Render.
	segment.foregroundResolved = false
	segment.backgroundResolved = false

	segment.writer.SetIndex(index)
	segment.Enabled = true
	segment.SetText(text)

	// Intentionally skip setCache(): the writer is zero/partially hydrated
	// here, and caching it would make restoreCache() later resurrect a
	// disabled writer as enabled while rendering the main template against
	// empty data.
	template.Cache.AddSegmentData(segment.Name(), segment.writer)

	return true
}

func (segment *Segment) Text() string {
	return segment.writer.Text()
}

func (segment *Segment) SetText(text string) {
	segment.writer.SetText(text)
}

func (segment *Segment) ResolveForeground() color.Ansi {
	if segment.foregroundResolved {
		return segment.foregroundCache
	}

	if len(segment.ForegroundTemplates) != 0 {
		match := segment.ForegroundTemplates.FirstMatch(segment.writer, segment.Foreground.String())
		segment.Foreground = color.Ansi(match)
	}

	segment.foregroundCache = segment.Foreground
	segment.foregroundResolved = true

	return segment.foregroundCache
}

func (segment *Segment) ResolveBackground() color.Ansi {
	if segment.backgroundResolved {
		return segment.backgroundCache
	}

	if len(segment.BackgroundTemplates) != 0 {
		match := segment.BackgroundTemplates.FirstMatch(segment.writer, segment.Background.String())
		segment.Background = color.Ansi(match)
	}

	segment.backgroundCache = segment.Background
	segment.backgroundResolved = true

	return segment.backgroundCache
}

func (segment *Segment) ResolveStyle() SegmentStyle {
	if len(segment.styleCache) != 0 {
		return segment.styleCache
	}

	segment.styleCache = segment.Style.resolve(segment.writer)

	return segment.styleCache
}

func (segment *Segment) IsPowerline() bool {
	style := segment.ResolveStyle()
	return style == Powerline || style == Accordion
}

func (segment *Segment) HasEmptyDiamondAtEnd() bool {
	if segment.ResolveStyle() != Diamond {
		return false
	}

	return segment.TrailingDiamond == ""
}

func (segment *Segment) hasCache() bool {
	return segment.Cache != nil && !segment.Cache.Duration.IsEmpty()
}

// DataKey returns the identity used to look up segment data: the segment's
// alias if set, falling back to its type.
func (segment *Segment) DataKey() string {
	if segment.Alias != "" {
		return segment.Alias
	}

	return string(segment.Type)
}

// Writer returns the segment's underlying SegmentWriter.
func (segment *Segment) Writer() SegmentWriter {
	return segment.writer
}

func (segment *Segment) isToggled() bool {
	togglesMap, OK := cache.Get[map[string]bool](cache.Session, cache.TOGGLECACHE)
	if !OK || len(togglesMap) == 0 {
		log.Debug("no toggles found")
		return false
	}

	if togglesMap[segment.DataKey()] {
		log.Debugf("segment toggled off: %s", segment.Name())
		return true
	}

	return false
}

func (segment *Segment) restoreCache() bool {
	if !segment.hasCache() {
		return false
	}

	key, store := segment.cacheKeyAndStore()

	data, OK := cache.Get[any](store, key)
	if !OK {
		log.Debugf("no cache found for segment: %s, key: %s", segment.Name(), key)
		return false
	}

	switch v := data.(type) {
	case SegmentWriter:
		segment.writer = v
		segment.Enabled = true
		template.Cache.AddSegmentData(segment.Name(), segment.writer)
		log.Debug("restored segment from cache: ", segment.Name())
		segment.restored = true
		return true
	case string:
		// legacy JSON cache entry, remove it so it gets re-cached with the new format
		log.Debugf("removing legacy cache key: %s", key)
		cache.Delete(store, key)
		return false
	default:
		log.Debugf("unexpected cache type for segment: %s, key: %s", segment.Name(), key)
		cache.Delete(store, key)
		return false
	}
}

// restoreData replays a segment's writer state from the data file supplied via
// runtime.Flags.SegmentData, bypassing the real runtime entirely. This lets
// segments render from a recorded fixture instead of probing the environment.
func (segment *Segment) restoreData() bool {
	data, OK := segment.env.Flags().SegmentData[segment.DataKey()]
	if !OK {
		return false
	}

	err := json.Unmarshal(data, &segment.writer)
	if err != nil {
		log.Error(err)
		return false
	}

	segment.Enabled = true
	segment.restored = true

	template.Cache.AddSegmentData(segment.Name(), segment.writer)

	log.Debug("restored segment from data: ", segment.Name())

	return true
}

func (segment *Segment) setCache() {
	if segment.restored || !segment.hasCache() {
		return
	}

	// Never cache pending state to avoid polluting cache with incomplete data
	if segment.Pending {
		return
	}

	// TODO: check if we can make segmentwriter a generic Type indicator
	// that way we can actually get the value straight from cache.Get
	// and marchalling is obsolete
	key, store := segment.cacheKeyAndStore()
	cache.Set(store, key, segment.writer, segment.Cache.Duration)
}

func (segment *Segment) cacheKeyAndStore() (string, cache.Store) {
	format := "segment_cache_%s"
	switch segment.Cache.Strategy {
	case Session:
		return fmt.Sprintf(format, segment.Name()), cache.Session
	case Device:
		return fmt.Sprintf(format, segment.Name()), cache.Device
	case Folder:
		fallthrough
	default:
		return fmt.Sprintf(format, strings.Join([]string{segment.Name(), segment.folderKey()}, "_")), cache.Device
	}
}

func (segment *Segment) folderKey() string {
	key, ok := segment.writer.CacheKey()
	if !ok {
		return segment.env.Pwd()
	}

	return key
}

func (segment *Segment) string() string {
	// Use simple pending text if segment is still pending
	if segment.Pending {
		if segment.Placeholder != "" {
			return segment.Placeholder
		}

		return "..."
	}

	result := segment.Templates.Resolve(segment.writer, "", segment.TemplatesLogic)
	if len(result) != 0 {
		return result
	}

	if segment.Template == "" {
		segment.Template = segment.writer.Template()
	}

	text, err := template.Render(segment.Template, segment.writer)
	if err != nil {
		return err.Error()
	}

	return text
}

func (segment *Segment) shouldIncludeFolder() bool {
	if segment.env == nil {
		return true
	}

	cwdIncluded := segment.cwdIncluded()
	cwdExcluded := segment.cwdExcluded()

	return cwdIncluded && !cwdExcluded
}

func (segment *Segment) cwdIncluded() bool {
	if len(segment.IncludeFolders) == 0 {
		return true
	}

	return segment.env.DirMatchesOneOf(segment.env.Pwd(), segment.IncludeFolders)
}

func (segment *Segment) cwdExcluded() bool {
	return segment.env.DirMatchesOneOf(segment.env.Pwd(), segment.ExcludeFolders)
}

func (segment *Segment) evaluateNeeds() {
	if segment.needsEvaluated {
		return
	}

	segment.needsEvaluated = true

	value := segment.Template
	if value == "" && segment.writer != nil {
		value = segment.writer.Template()
	}

	if len(segment.ForegroundTemplates) != 0 {
		value += strings.Join(segment.ForegroundTemplates, "")
	}

	if len(segment.BackgroundTemplates) != 0 {
		value += strings.Join(segment.BackgroundTemplates, "")
	}

	if len(segment.Templates) != 0 {
		value += strings.Join(segment.Templates, "")
	}

	if segment.FallbackTemplate != "" {
		value += segment.FallbackTemplate
	}

	if !strings.Contains(value, ".Segments.") {
		return
	}

	matches := regex.FindAllNamedRegexMatch(`\.Segments\.(?P<NAME>[a-zA-Z0-9]+)`, value)
	for _, name := range matches {
		segmentName := name["NAME"]

		if len(name) == 0 || slices.Contains(segment.Needs, segmentName) {
			continue
		}

		segment.Needs = append(segment.Needs, segmentName)
	}
}

func (segment *Segment) key() any {
	if segment.Index > 0 {
		return segment.Index - 1
	}

	return segment.Name()
}

package cache

import (
	"encoding/gob"
	"errors"
	"time"
)

// ErrLocked is returned by openFile when the cache file is held exclusively
// by another process (e.g. a Windows sharing violation that persisted past
// the retry window). Callers must treat this as "leave the file alone":
// operate purely in-memory for this run and do not recreate/truncate the
// file on close.
var ErrLocked = errors.New("cache file is locked by another process")

func init() {
	gob.Register(&Entry[any]{})
	gob.Register(Template{})
	gob.Register(SimpleTemplate{})
	gob.Register((*Duration)(nil))
	gob.Register(map[string]bool{})
	gob.Register(commandPathEntry{})
}

const (
	DeviceStore = "omp.cache"
)

const (
	TEMPLATECACHE    = "template_cache"
	TOGGLECACHE      = "toggle_cache"
	PROMPTCOUNTCACHE = "prompt_count_cache"
	ENGINECACHE      = "engine_cache"
	FONTLISTCACHE    = "font_list_cache"
	CLAUDECACHE      = "claude_cache"
	COPILOTCLICACHE  = "copilot_cli_cache"
)

type Entry[T any] struct {
	Value     T
	Timestamp int64
	TTL       int
}

func (c *Entry[T]) Expired() bool {
	if c.TTL < 0 {
		return false
	}

	return time.Now().Unix() >= (c.Timestamp + int64(c.TTL))
}

package cache

import (
	"encoding/gob"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/jandedobbeleer/oh-my-posh/src/log"
	"github.com/jandedobbeleer/oh-my-posh/src/maps"
)

type store struct {
	cache    *maps.Concurrent[*Entry[any]]
	filePath string
	dirty    bool
	persist  bool
	// locked is set when the on-disk cache file could not be opened because
	// another process holds it (e.g. Windows sharing violation that
	// persisted past the retry window). When true, the store operates
	// purely in-memory for the lifetime of this process: close() must not
	// attempt to (re)create the file, since doing so would truncate the
	// other process's data.
	locked bool
}

var (
	session *store
	device  *store
)

type Store string

const (
	Session Store  = "session"
	Device  Store  = "device"
	TTL     string = "ttl"
)

func (s Store) new() *store {
	return &store{
		cache: maps.NewConcurrent[*Entry[any]](),
	}
}

// getStore returns the appropriate store based on the Store identifier
func (s Store) get() *store {
	switch s {
	case Device:
		if device == nil {
			device = s.new()
		}

		return device
	default:
		if session == nil {
			session = s.new()
		}

		return session
	}
}

// Init initializes a store with the given file path
func (s Store) init(filePath string, persist bool) {
	defer log.Trace(time.Now(), string(s), filePath)

	store := s.get()
	store.cache = maps.NewConcurrent[*Entry[any]]()
	store.filePath = filepath.Join(Path(), filePath)
	store.persist = persist
	store.dirty = false
	store.locked = false

	reader, err := openFile(store.filePath)
	if err != nil {
		if errors.Is(err, ErrLocked) {
			// Another process holds the file. Leave it alone: run this
			// session purely in-memory, don't mark dirty, don't recreate
			// on close.
			log.Debugf("(%s) cache file is locked, running in-memory only", string(s))
			store.locked = true
			return
		}

		// set to dirty so we create it on close
		log.Error(err)
		store.dirty = true
		return
	}

	defer reader.Close()

	var list maps.Simple[*Entry[any]]

	dec := gob.NewDecoder(reader)
	if err := dec.Decode(&list); err != nil {
		log.Error(err)
		// If gob decoding fails, the cache file might be from the old format
		// Set dirty to true so we recreate it in gob format
		store.dirty = true
		return
	}

	for key, entry := range list {
		if entry.Expired() {
			log.Debugf("(%s) skipping expired key: %s", string(s), key)
			continue
		}

		log.Debugf("(%s) loading %s", string(s), key)
		store.cache.Set(key, entry)
	}
}

// touchSessionFile updates the session file's modification time if it's older than 1 hour.
// This prevents stale session cache files from being cleaned up while reducing steady-state overhead.
func touchSessionFile(filePath string) {
	info, err := os.Stat(filePath)
	if err != nil {
		return
	}

	if time.Since(info.ModTime()) <= time.Hour {
		return
	}

	if err := os.Chtimes(filePath, time.Now(), time.Now()); err != nil {
		log.Error(err)
	}
}

func (s Store) close() {
	defer log.Trace(time.Now(), string(s))

	store := s.get()
	if store == nil || store.locked || !store.persist || !store.dirty {
		if s == Session && store != nil && !store.locked && store.filePath != "" {
			touchSessionFile(store.filePath)
		}

		log.Debugf("(%s) not persisting", string(s))
		return
	}

	cache := store.cache.ToSimple()

	file, err := openFileForWrite(store.filePath)
	if err != nil {
		if errors.Is(err, ErrLocked) {
			// Became locked between init and close (e.g. another process
			// started writing meanwhile) — do not recreate/truncate.
			log.Debugf("(%s) cache file locked on close, skipping persist", string(s))
			return
		}

		log.Error(err)
		return
	}

	defer func() {
		if err := file.Close(); err != nil {
			log.Error(err)
		}
	}()

	enc := gob.NewEncoder(file)
	if err := enc.Encode(cache); err != nil {
		log.Error(err)
	}
}

// Get retrieves a typed value from the specified store
func Get[T any](s Store, key string) (T, bool) {
	var zero T
	defer log.Trace(time.Now(), string(s), key)

	store := s.get()
	if store == nil {
		log.Debugf("(%s) store is nil", string(s))
		return zero, false
	}

	entry, found := store.cache.Get(key)
	if !found {
		log.Debugf("(%s) key not found: %s", string(s), key)
		return zero, false
	}

	if entry.Expired() {
		log.Debugf("(%s) key expired: %s", string(s), key)
		store.cache.Delete(key)
		store.dirty = true
		return zero, false
	}

	// Type assertion to get the typed value
	if typed, ok := entry.Value.(T); ok {
		log.Debugf("(%s) found entry: %s - %v", string(s), key, typed)
		return typed, true
	}

	log.Error(fmt.Errorf("(%s) type mismatch for key: %s. Got %T, expected %T", string(s), key, entry.Value, zero))
	return zero, false
}

// Set stores a typed value in the specified store
func Set[T any](s Store, key string, value T, duration Duration) {
	defer log.Trace(time.Now(), string(s), key)

	store := s.get()
	if store == nil {
		log.Debugf("(%s) store is nil", string(s))
		return
	}

	seconds := duration.Seconds()
	if seconds == 0 {
		return
	}

	log.Debugf("(%s) setting entry: %s - %v with duration: %s", string(s), key, value, string(duration))

	store.cache.Set(key, &Entry[any]{
		Value:     value,
		Timestamp: time.Now().Unix(),
		TTL:       seconds,
	})

	store.dirty = true
}

// Delete removes a key from the specified store
func Delete(s Store, key string) {
	defer log.Trace(time.Now(), string(s), key)

	store := s.get()
	if store == nil {
		log.Debugf("(%s) store is nil", string(s))
		return
	}

	log.Debugf("(%s) deleting key: %s", string(s), key)
	store.cache.Delete(key)
	store.dirty = true
}

func DeleteAll(s Store) {
	defer log.Trace(time.Now(), string(s))

	store := s.get()
	if store == nil {
		log.Debugf("(%s) store is nil", string(s))
		return
	}

	store.cache = maps.NewConcurrent[*Entry[any]]()
	store.dirty = true
}

func Print(s Store) string {
	defer log.Trace(time.Now(), string(s))

	store := s.get()
	if store == nil {
		return fmt.Sprintf("Store %s is nil", string(s))
	}

	cache := store.cache.ToSimple()
	if len(cache) == 0 {
		return fmt.Sprintf("Store %s is empty", string(s))
	}

	var builder strings.Builder

	for key, entry := range cache {
		builder.WriteString("\n")

		if entry.Expired() {
			fmt.Fprintf(&builder, "Key: %s [EXPIRED]\n", key)
			builder.WriteString("\n")
			continue
		}

		var ttlInfo string
		if entry.TTL < 0 {
			ttlInfo = "never expires"
		}
		if entry.TTL >= 0 {
			expiresAt := time.Unix(entry.Timestamp+int64(entry.TTL), 0)
			ttlInfo = fmt.Sprintf("expires at %s", expiresAt.Format("2006-01-02 15:04:05"))
		}

		fmt.Fprintf(&builder, "Key: %s\n", key)
		fmt.Fprintf(&builder, "  Value: %s\n", fmt.Sprintf("%#v", entry.Value))
		fmt.Fprintf(&builder, "  Type: %T\n", entry.Value)
		fmt.Fprintf(&builder, "  Created: %s\n", time.Unix(entry.Timestamp, 0).Format("2006-01-02 15:04:05"))
		fmt.Fprintf(&builder, "  TTL: %s\n", ttlInfo)
	}

	return builder.String()
}

package template

import (
	"encoding/json"
	"strconv"
	"strings"
	"time"

	"github.com/jandedobbeleer/oh-my-posh/src/build"
	"github.com/jandedobbeleer/oh-my-posh/src/cache"
	"github.com/jandedobbeleer/oh-my-posh/src/log"
	"github.com/jandedobbeleer/oh-my-posh/src/maps"
	"github.com/jandedobbeleer/oh-my-posh/src/runtime"
	"github.com/jandedobbeleer/oh-my-posh/src/runtime/path"
)

var (
	Cache *cache.Template

	// routedEnvDataKeys are env-section keys the CLI layer already routes into
	// runtime.Flags before Init runs (see runtime.Flags.EnvData), so by the
	// time loadCache runs, env.Pwd()/StatusCodes()/ExecutionTime() already
	// reflect the flag-precedence-resolved value (CLI flag > data file >
	// live). They must never be applied a second time here, or a raw file
	// value could clobber that resolved value. A key belongs here if and only
	// if applyDataFile routes it - listing one it does not route would instead
	// make that key unsettable from a data file.
	routedEnvDataKeys = []string{"PWD", "Code", "ExecutionTime", "PipeStatus", "Interrupted"}
)

func loadCache(vars maps.Simple[any], aliases *maps.Config) {
	if !env.Flags().IsPrimary {
		// Load the template cache for a non-primary prompt before rendering any templates.
		if OK := restoreCache(); OK {
			// Interrupted is a per-invocation flag, never a cached value: the
			// restored blob was saved by the primary prompt (never interrupted),
			// so it must be refreshed from the current flags.
			Cache.Interrupted = env.Flags().Interrupted
			return
		}
	}

	// Build fully before assigning: a long-lived process (serve) rebuilds
	// this per prompt while goroutines from an abandoned render cycle may
	// still read the global - they must only ever observe a complete object.
	tmpl := new(cache.Template)

	tmpl.Root = env.Root()
	tmpl.Shell = env.Shell()
	tmpl.ShellVersion = env.Flags().ShellVersion
	tmpl.Code, _ = env.StatusCodes()
	tmpl.Interrupted = env.Flags().Interrupted
	tmpl.WSL = env.IsWsl()
	tmpl.Segments = maps.NewConcurrent[any]()
	tmpl.PromptCount = env.Flags().PromptCount
	tmpl.Var = make(map[string]any)
	tmpl.Jobs = env.Flags().JobCount
	tmpl.Version = build.Version

	if vars != nil {
		tmpl.Var = vars
	}

	pwd := env.Pwd()
	tmpl.PWD = path.ReplaceHomeDirPrefixWithTilde(pwd)

	tmpl.AbsolutePWD = pwd
	if env.IsWsl() {
		tmpl.AbsolutePWD, _ = env.RunCommand("wslpath", "-m", pwd)
	}

	env.Flags().AbsolutePWD = tmpl.AbsolutePWD
	tmpl.PSWD = env.Flags().PSWD

	tmpl.Folder = path.Base(pwd)
	if env.GOOS() == runtime.WINDOWS && strings.HasSuffix(tmpl.Folder, ":") {
		tmpl.Folder += `\`
	}

	tmpl.UserName = env.User()
	if host, err := env.Host(); err == nil {
		tmpl.HostName = host
	}

	goos := env.GOOS()
	tmpl.OS = goos
	if goos == runtime.LINUX {
		tmpl.OS = env.Platform()
	}

	val := env.Getenv("SHLVL")
	if shlvl, err := strconv.Atoi(val); err == nil {
		tmpl.SHLVL = shlvl
	}

	overlayEnvData(tmpl)

	// Alias mapping must apply to a data-provided value exactly as it does to
	// a live one, so it runs after the overlay, on whichever value won.
	tmpl.Shell = aliases.GetShellName(tmpl.Shell)
	tmpl.UserName = aliases.GetUserName(tmpl.UserName)
	tmpl.HostName = aliases.GetHostName(tmpl.HostName)

	Cache = tmpl
}

// overlayEnvData merges the data file's env section onto an already-built
// template cache. It only touches keys present in the data, so anything not
// specified keeps its live value. Keys the CLI layer already routed into
// runtime.Flags (see routedEnvDataKeys) are stripped first so a raw file
// value can never clobber the flag-precedence-resolved value. Failures are
// logged, never fatal - the prompt renders with live values regardless.
func overlayEnvData(tmpl *cache.Template) {
	data := env.Flags().EnvData
	if len(data) == 0 {
		return
	}

	var fields map[string]json.RawMessage
	if err := json.Unmarshal(data, &fields); err != nil {
		log.Error(err)
		return
	}

	for _, key := range routedEnvDataKeys {
		delete(fields, key)
	}

	// SegmentsCache/Segments are internal cache plumbing, not user-facing
	// template data; a data file must never be able to overwrite them. Var
	// (template vars) is left alone - overriding it from the data file is
	// intentional and useful.
	delete(fields, "SegmentsCache")
	delete(fields, "Segments")

	overlay, err := json.Marshal(fields)
	if err != nil {
		log.Error(err)
		return
	}

	if err := json.Unmarshal(overlay, &tmpl.SimpleTemplate); err != nil {
		log.Error(err)
	}
}

func restoreCache() bool {
	defer log.Trace(time.Now())

	val, OK := cache.Get[cache.SimpleTemplate](cache.Session, cache.TEMPLATECACHE)
	if !OK {
		return false
	}

	Cache = new(cache.Template)
	Cache.SimpleTemplate = val
	Cache.Segments = Cache.SegmentsCache.ToConcurrent()

	return true
}

func SaveCache() {
	// only store this when in a primary prompt
	// and when we have any extra prompt in the config
	canSave := env.Flags().IsPrimary && env.Flags().HasExtra
	if !canSave {
		return
	}

	Cache.SegmentsCache = Cache.Segments.ToSimple()

	cache.Set(cache.Session, cache.TEMPLATECACHE, &Cache.SimpleTemplate, cache.ONEDAY)
}

